function [nmbScn,scan,scnDir] = fScanDirLstV01(mDir,inScn)%% search directory, return number of scan, scan array, scan directory%% [nmbScn,scan,scnDir] = fScanDirLstV01(mDir,inScn)% nmbScn: number of scan to go through% scan: array of scan numbers% scnDir: scan directory to go through% mDir: mother directory% inScan: input scan to go through (not necessary to exist)%% Written by Kei Nakamura% Created on Monday, June 1st 2009.% Modified on%% main bodyinfrm = dir([mDir,'/Scan*']);         % information for Scan* file[nmbScn,dlt] = size(infrm);   % number of scansnmbInScn = max(size(inScn));  % number of input scanii = 1;     % index for infojj = 1;     % index for inScnkk = 1;     % index for outScnscnDir{1} = 'null';           % in case scan doesn't exist, to retun nullscan(1) = -1;                   % nullwhile jj<=nmbInScn          % go through all inScn       name = infrm(ii).name;    scnNmb = str2num(name(5:end));  % scan number    while inScn(jj)<scnNmb  % input scan is smaller, go next inScn        jj = jj + 1;    end            if inScn(jj)==scnNmb & infrm(ii).isdir   % if file is directory, and =input scan        scnDir{kk} = name;        scan(kk) = scnNmb;            % output scan (exist and input)        kk = kk+1;        jj = jj+1;    end    ii = ii+1;endnmbScn = kk -1; % number of scans for output
